    record['Amount'] = int(record['Amount'])

disaster_projects_2022 = []

for doc in civic_docs:
    text = doc['text']
    lines = text.split('\n')

    for i, line in enumerate(lines):
        line = line.strip()
        if not line:
            continue

        if '(FEMA Project)' in line or '(CalOES Project)' in line or '(CalJPIA Project)' in line:
            project_name = line

            has_2022 = False
            start_index = max(0, i-10)
            end_index = min(len(lines), i+20)

            for j in range(start_index, end_index):
                context_line = lines[j]
                if '2022' in context_line:
                    lower_line = context_line.lower()
                    if 'begin' in lower_line or 'start' in lower_line or 'advertise' in lower_line or 'complete design' in lower_line:
                        has_2022 = True
                        break

            if has_2022:
                disaster_projects_2022.append(project_name)

disaster_projects_2022 = list(set(disaster_projects_2022))

result = {
    'count': len(disaster_projects_2022),
    'projects': disaster_projects_2022
}

print('__RESULT__:')
print(json.dumps(result))"}

